import machine
import time
import network
from umqtt.simple import MQTTClient
import random

# Wi-Fi credentials
SSID = 'your_SSID'
PASSWORD = 'your_PASSWORD'

# MQTT broker details
BROKER_IP = 'broker_ip'
CLIENT_ID = 'esp32_client'

# Connect to Wi-Fi
def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    wlan.connect(SSID, PASSWORD)
    
    while not wlan.isconnected():
        time.sleep(1)
    print('Connected to Wi-Fi:', wlan.ifconfig())

# Publish temperature data
def publish_temperature(client):
    while True:
        temperature = random.uniform(20.0, 30.0)  # Simulated temperature data
        client.publish(b'sensors/temp', str(temperature).encode())
        print('Published temperature:', temperature)
        time.sleep(10)  # Publish every 10 seconds

# Main function
def main():
    connect_wifi()
    client = MQTTClient(CLIENT_ID, BROKER_IP)
    client.connect()
    publish_temperature(client)

# Run the main function
main()